                    Climatisation Wi-Fi Cuisine Espace de travail Fer à repasser
                    Sèche-cheveux Cintres
                </p>
            </div>

            <div className="dropdown">
                <p className="title">Equipements</p>
                <p className="content">
                    Climatisation Wi-Fi Cuisine Espace de travail Fer à repasser
                    Sèche-cheveux Cintres
                </p>
            </div>
        </div>
    );
}

export default Dropdown;
